#!/usr/bin/perl
use strict;
use warnings;
use PDF::API2;

sub extract_data {
    my ($pdf_file) = @_;

    # Open the PDF file
    my $pdf = PDF::API2->open($pdf_file);

    foreach my $page (1 .. $pdf->pages) {
        my $text = $pdf->page($page)->text();
        # Process the text as needed
        while ($text =~ /Author: ([^\n]+)/g) {
            print "Author: $1\n";
        }
        while ($text =~ /Date: ([^\n]+)/g) {
            print "Date: $1\n";
        }
        while ($text =~ /Table: ([^\n]+)/g) {
            print "Table: $1\n";
        }
    }
}

# Replace 'example.pdf' with the path to the PDF file you want to process.
extract_data('example.pdf');
